/*
A volumetric RC implementation
    Scene
        Volume resolution is 32X32X48, with 6 hemispheres per voxel
        Everything is dynamic, temporal merging means some light lag is inevitable
    Rays
        A hemisphere traces (3x3)*(4^N) rays, where N is the LOD <- (0, 1, 2, 3, ..)
    Probe placement
        Must decide where we trace rays from inside the voxel
        Very simple implementation in this shader -> choose the first empty voxel near the center if it exists
            A better approach is beyond this shader :)
    Merging
        Weighted trilinear interpolation is used
        Visibility determines the weight
            Is computed by projecting lower cascades on the higher cascade probes to determine visibility
            Uses the nearest hemisphere and its traced rays -> one texture fetch for visibility
    Performance
        Rays with almost the same direction are traced close to each other in the cubemap
        Use acceleration structure when tracing rays
    These are examples of other improvements:
        Probe placement inside voxels
            Find probe position using volume mipmaps
        Overlap between 6 hemispheres in one voxel
            A lot of rays cover the same directions from the same origin -> bad
            But don't want to lose cos(theta) in the integral if rays are shared between hemispheres
                Could store multiple weights per rays for the 3 closest hemispheres (max 3 hemisphere overlap)
            Other implementations might have solved this ..



Controls:
    Animation stops when the mouse is used
        WASD - move the camera
        Space - move faster
        Mouse - rotate the camera
*/


vec4 TextureCube(vec2 uv) {
    float tcSign = -mod(floor(uv.y*I1024), 2.)*2. + 1.;
    vec3 tcD = vec3(vec2(uv.x, mod(uv.y, 1024.))*I512 - 1., tcSign);
    if (uv.y > 4096.) tcD = tcD.xzy;
    else if (uv.y > 2048.) tcD = tcD.zxy;
    return textureLod(iChannel3, tcD, 0.);
}

vec3 IntegrateVoxel(vec3 p, vec3 n) {
    vec3 l = vec3(0.);
    vec2 cubeUV = vec2(p.x + floor(p.y)*32., p.z);
    float normalOffset;
    vec3 an = abs(n);
    if (an.x > max(an.y, an.z)) normalOffset = ((n.x < 0.)? 0. : 48.)*9.;
    else if (an.y > an.z) normalOffset = ((n.y < 0.)? 48.*2. : 48.*3.)*9.;
    else normalOffset = ((n.z < 0.)? 48.*4. : 48.*5.)*9.;
    for (float i = 0.; i < 8.5; i++) {
        l += TextureCube(cubeUV + vec2(0., normalOffset + i*48.)).xyz;
    }
    return l;
}

float SampleDotShadow(vec3 p, vec3 n) {
    vec3 SUN_DIR = GetSunDir(iTime);
    vec3 SUN_TAN = normalize(cross(SUN_DIR, vec3(0., 1., 0.)));
    vec3 SUN_BIT = cross(SUN_TAN, SUN_DIR);
    vec3 an = abs(n);
    vec3 nt, nb;
    if (an.x > max(an.y, an.z)) {
        nt = vec3(0., 0., 1.);
        nb = vec3(0., 1., 0.);
    } else if (an.y > an.z) {
        nt = vec3(1., 0., 0.);
        nb = vec3(0., 0., 1.);
    } else {
        nt = vec3(1., 0., 0.);
        nb = vec3(0., 1., 0.);
    }
    float o = 0.;
    for (float x = -0.15; x < 0.2; x += 0.15) {
        for (float y = -0.15; y < 0.2; y += 0.15) {
            vec3 sp = p + nt*x + nb*y;
            vec3 smPos = sp - (vec3(16., 16., 24.) + SUN_DIR*SUN_DIST);
            vec2 smUV = vec2(dot(smPos, SUN_TAN), dot(smPos, SUN_BIT))/SUN_SM_SIZE/ASPECT*0.5 + 0.5;
            if (texture(iChannel2, smUV).w > dot(smPos, -SUN_DIR)) o += 1.;
        }
    }
    return max(0., dot(SUN_DIR, n))*o/9.;
}

vec4 Trace(vec3 p, vec3 d, out vec3 vp, out vec4 vc) {
    vec4 info = vec4(vec3(0.), 100000.);
    vec3 signdir = (max(vec3(0.), sign(d))*2. - 1.);
    vec3 iDir = 1./d;
    float bbDF = DFBox(p, vec3(32., 32., 48.));
    vec2 bb = ABox(p, iDir, vec3(0.01), vec3(31.99, 31.99, 47.99));
    if (bbDF > 0. && (bb.x < 0. || bb.y < bb.x)) return vec4(-10.);
    float tFAR = bb.y;
    float t = ((bbDF < 0.)? 0. : bb.x + 0.001);
    vec3 cp;
    vec4 sC;
    vec3 fp = floor(p + d*t);
    vec3 lfp = fp - vec3(0., 1., 0.);
    for (int i = 0; i < 128; i++) {
        if (t > tFAR) break;
        cp = p + d*t;
        sC = texture(iChannel1, vec2(fp.x + (mod(fp.y + 0.5, 8.) - 0.5)*32. + 0.5, fp.z + floor(fp.y*0.125)*48. + 0.5)*IRES);
        if (sC.w > 0.5) {
            vp = lfp + 0.5;
            vc = sC;
            return vec4(lfp - fp, t);
        }
        lfp = fp;
        fp += ABoxfarNormal(p, iDir, signdir, fp, fp + 1., t);
    }
    return vec4(-10.);
}

vec3 AcesFilm(vec3 x) {
    return clamp((x*(2.51*x + 0.03))/(x*(2.43*x + 0.59) + 0.14), 0., 1.);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec3 color = vec3(0.);
    vec3 cameraPos = texture(iChannel0, vec2(3.5, 0.5)*IRES).xyz;
    vec3 cameraEye = texture(iChannel0, vec2(2.5, 0.5)*IRES).xyz;
    vec3 pDir = normalize(vec3((fragCoord*IRES*2. - 1.)*ASPECT, 1.)*TBN(cameraEye));
    vec3 pPos;
    vec4 pCol;
    vec4 pHit = Trace(cameraPos, pDir, pPos, pCol);
    if (pHit.x > -1.5) {
        if (pCol.w > 1.5) {
            color = pCol.xyz;
        } else {
            color += IntegrateVoxel(pPos, pHit.xyz);
            color += SampleDotShadow(cameraPos + pDir*pHit.w + pHit.xyz*0.25, pHit.xyz)*GetSunLight(iTime);
            color *= pCol.xyz;
        }
    } else {
        color += GetSkyLight(pDir, iTime);
    }
    fragColor = vec4(pow(AcesFilm(max(vec3(0.), color)), vec3(0.45)), 1.);
}

//CONST
const float PI = 3.141592653;
const float I3 = 1./3.;
const float I9 = 1./9.;
const float I12 = 1./12.;
const float I32 = 1./32.;
const float I48 = 1./48.;
const float I256 = 1./256.;
const float I512 = 1./512.;
const float I1024 = 1./1024.;
const float SUN_DIST = 48.;
const float SUN_SM_SIZE = 32.;
const float ISUNRT = 2.*PI/16.;
const float SUNRTO = 1.15;

//DEFINE
#define RES iChannelResolution[0].xy
#define IRES 1./iChannelResolution[0].xy
#define ASPECT vec2(iChannelResolution[0].x/iChannelResolution[0].y,1.)

//MATH
vec3 BRDF_GGX(vec3 w_o, vec3 w_i, vec3 n, float alpha, vec3 F0) {
    vec3 h = normalize(w_i + w_o);
    float a2 = alpha*alpha;
    float D = a2/(3.141592653*pow(pow(dot(h, n), 2.)*(a2 - 1.) + 1., 2.));
    vec3 F = F0 + (1. - F0)*pow(1. - dot(n, w_o), 5.);
    float k = a2*0.5;
    float G = 1./((dot(n, w_i)*(1. - k) + k)*(dot(n, w_o)*(1. - k) + k));
    vec3 OUT = F*(D*G*0.25);
    return ((isnan(OUT) != bvec3(false)) ? vec3(0.) : OUT);
}

mat3 TBN(vec3 N) {
    vec3 Nb, Nt;
    if (abs(N.y) > 0.999) {
        Nb = vec3(1., 0., 0.);
        Nt = vec3(0., 0., 1.);
    } else {
    	Nb = normalize(cross(N, vec3(0., 1., 0.)));
    	Nt = normalize(cross(Nb, N));
    }
    return mat3(Nb.x, Nt.x, N.x, Nb.y, Nt.y, N.y, Nb.z, Nt.z, N.z);
}

float smin(float a, float b, float k) {
    //https://iquilezles.org/articles/smin
    float h = max(k-abs(a-b),0.)/k;
    return min(a,b)-h*h*h*k*(1.0/6.0);
}

float DFBox(vec2 p, vec2 b) {
    vec2 d = abs(p - b*0.5) - b*0.5;
    return min(max(d.x, d.y), 0.) + length(max(d, 0.));
}

float DFBox(vec3 p, vec3 b) {
    vec3 d = abs(p - b*0.5) - b*0.5;
    return min(max(d.x, max(d.y, d.z)), 0.) + length(max(d, 0.));
}

vec2 ABox(vec3 origin, vec3 idir, vec3 bmin, vec3 bmax) {
    vec3 tMin = (bmin - origin)*idir;
    vec3 tMax = (bmax - origin)*idir;
    vec3 t1 = min(tMin, tMax);
    vec3 t2 = max(tMin, tMax);
    return vec2(max(max(t1.x, t1.y), t1.z), min(min(t2.x, t2.y), t2.z));
}

vec3 ABoxfarNormal(vec3 origin, vec3 idir, vec3 signdir, vec3 bmin, vec3 bmax, out float dist) {
    vec3 tMin = (bmin - origin)*idir;
    vec3 tMax = (bmax - origin)*idir;
    vec3 t2 = max(tMin, tMax);
    dist = min(min(t2.x, t2.y), t2.z);
    if (t2.x < min(t2.y, t2.z)) return vec3(signdir.x, 0., 0.);
    else if (t2.y < t2.z) return vec3(0., signdir.y, 0.);
    else return vec3(0., 0., signdir.z);
}

//SCENE
vec3 GetSkyLight(vec3 d, float t) {
    return vec3(0.75, 0.85, 1.)*1.25*pow(d.y*0.5 + 0.5, 2.);
}

vec3 GetSunLight(float t) {
    return vec3(2., 1.5, 1.25);
}

vec3 GetSunDir(float t) {
    float aniT = t*(1. - exp(-t*0.2));
    float sunA = aniT*ISUNRT + SUNRTO;
    float sunT = (pow(cos(aniT*ISUNRT*0.25), 5.)*0.5 + 0.5)*2. + 0.2;
    return normalize(vec3(sin(sunA), sunT, cos(sunA)));
}

//HEMISPHERE
vec3 ComputeDirEven(vec2 uv, float probeSize) {
    vec2 probeRel = uv - probeSize*0.5;
    float probeThetai = max(abs(probeRel.x), abs(probeRel.y));
    float probeTheta = probeThetai/probeSize*3.14192653;
    float probePhi = 0.;
    if (probeRel.x + 0.5 > probeThetai && probeRel.y - 0.5 > -probeThetai) {
        probePhi = probeRel.x - probeRel.y;
    } else if (probeRel.y - 0.5 < -probeThetai && probeRel.x - 0.5 > -probeThetai) {
        probePhi = probeThetai*2. - probeRel.y - probeRel.x;
    } else if (probeRel.x - 0.5 < -probeThetai && probeRel.y + 0.5 < probeThetai) {
        probePhi = probeThetai*4. - probeRel.x + probeRel.y;
    } else if (probeRel.y + 0.5 > probeThetai && probeRel.x + 0.5 < probeThetai) {
        probePhi = probeThetai*8. - (probeRel.y - probeRel.x);
    }
    probePhi = probePhi*3.141592653*2./(4. + 8.*floor(probeThetai));
    return vec3(vec2(sin(probePhi), cos(probePhi))*sin(probeTheta), cos(probeTheta));
}

vec3 ComputeDir(vec2 uv, float probeSize) {
    if (probeSize > 4.5) return ComputeDirEven(uv, probeSize);
    vec2 probeRel = uv - 1.5;
    if (length(probeRel) < 0.1) return vec3(0., 0., 1.);
    float probePhi = atan(probeRel.x, probeRel.y) + 3.141592653*1.75;
    float probeTheta = 3.141592653*0.25;
    return vec3(vec2(sin(probePhi), cos(probePhi))*sin(probeTheta), cos(probeTheta));
}

vec2 ProjectDir(vec3 dir, float probeSize) {
    if (dir.z <= 0.) return vec2(-1.);
    float thetai = min(floor((1. - acos(length(dir.xy)/length(dir))/(3.141592653*0.5))*(probeSize*0.5)), probeSize*0.5 - 1.);
    float phiF = atan(-dir.x, -dir.y);
    float phiI = floor((phiF/3.141592653*0.5 + 0.5)*(4. + 8.*thetai) + 0.5) + 0.5;
    vec2 phiUV;
    float phiLen = 2.*thetai + 1.;
    float sideLen = phiLen + 1.;
    if (phiI < phiLen) phiUV = vec2(sideLen - 0.5, sideLen - phiI);
    else if (phiI < phiLen*2.) phiUV = vec2(sideLen - (phiI - phiLen), 0.5);
    else if (phiI < phiLen*3.) phiUV = vec2(0.5, phiI - phiLen*2.);
    else phiUV = vec2(phiI - phiLen*3., sideLen - 0.5);
    return vec2((probeSize - sideLen)*0.5) + phiUV;
}

//Vars

vec2 CameraEyeAngles(float t) {
    float aniT = t*(1. - exp(-t*0.2))*ISUNRT - 0.3;
    return vec2(-0.05 - (-cos(aniT)*0.5 + 0.5)*0.5, mod(-2.2 + (-cos(aniT*1.1)*0.5 + 0.5)*2., 2.*PI));
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec4 info = texture(iChannel0, fragCoord*IRES);
    if (iFrame == 0) {
        if (fragCoord.x < 10. && fragCoord.y < 1.) {
            if (fragCoord.x < 1.) info = vec4(0., 0., 0., 0.);
            else if (fragCoord.x < 2.) info = vec4(-0.05, -2.2, 0., 0.);
            else if (fragCoord.x < 3.) info = vec4(0., 0., 0., 1.);
            else if (fragCoord.x < 4.) info = vec4(30., 8., 33., 1.);
            else if (fragCoord.x < 5.) info = vec4(1.);
        }
    } else {
		if (fragCoord.x < 16. && fragCoord.y < 1.) {
            if (fragCoord.x < 1.) {
                //Mouse
                if (iMouse.z > 0.) {
                    if (info.w == 0.) {
                    	info.w = 1.;
                    	info.xy = iMouse.zw;
                    }
                } else info.w = 0.;
            } else if (fragCoord.x < 2.) {
                //Angles
                if (texture(iChannel0, vec2(4.5, 0.5)*IRES).x > 0.5) {
                    info.xy = CameraEyeAngles(iTime);
                    info.zw = info.xy;
                } else {
                    vec4 LMouse = texture(iChannel0, vec2(0.5, 0.5)*IRES);
                    if (LMouse.w == 0.)  info.zw = info.xy;
                    if (LMouse.w == 1.) {
                        info.x = info.z + (iMouse.y - LMouse.y)*0.01;
                        info.x = clamp(info.x, -2.8*0.5, 2.8*0.5);
                        //X led
                        info.y = info.w - (iMouse.x - LMouse.x)*0.02;
                        info.y = mod(info.y, 3.1415926*2.);
                    }
                }
            } else if (fragCoord.x < 3.) {
                //Player Eye
                vec2 Angles = texture(iChannel0, vec2(1.5, 0.5)*IRES).xy;
                if (texture(iChannel0, vec2(4.5, 0.5)*IRES).x > 0.5) Angles = CameraEyeAngles(iTime);
                info.xyz = normalize(vec3(cos(Angles.x)*sin(Angles.y), sin(Angles.x), cos(Angles.x)*cos(Angles.y)));
            } else if (fragCoord.x < 4.) {
                //Player Pos
                if (texture(iChannel0, vec2(4.5, 0.5)*IRES).x > 0.5) {
                    float aniT = iTime*(1. - exp(-iTime*0.2))*ISUNRT - 0.9;
                    info.xyz = vec3(28., 7.5, 40.) + vec3(0., (-cos(aniT*0.5)*0.5 + 0.5)*19., -(-cos(aniT)*0.5 + 0.5)*30.);
                } else {
                    float Speed = 5.*iTimeDelta;
                    if (texelFetch(iChannel1, ivec2(32, 0), 0).x > 0.) Speed = 16.*iTimeDelta;
                    vec3 Eye = texture(iChannel0, vec2(2.5, 0.5)*IRES).xyz;
                    if (texelFetch(iChannel1, ivec2(87, 0), 0).x > 0.) info.xyz += Eye*Speed; //W
                    if (texelFetch(iChannel1, ivec2(83, 0), 0).x > 0.) info.xyz -= Eye*Speed; //S
                    vec3 Tan = normalize(cross(vec3(Eye.x, 0., Eye.z), vec3(0., 1., 0.)));
                    if (texelFetch(iChannel1, ivec2(65, 0), 0).x > 0.) info.xyz -= Tan*Speed; //A
                    if (texelFetch(iChannel1, ivec2(68, 0), 0).x > 0.) info.xyz += Tan*Speed; //D
                }
            } else if (fragCoord.x < 5.) {
                //Animation flag
                if (iMouse.z > 0.) info.x = 0.;
            }
        }
    }
    fragColor = info;
}

//Radiance cascades

const float LOD_MAX_POS   = 5022.;
const float LOD_POS[5]    = float[5](0., 2592., 3888., 4536., 4860.);

vec4 TextureCube(vec2 uv) {
    float tcSign = -mod(floor(uv.y*I1024), 2.)*2. + 1.;
    vec3 tcD = vec3(vec2(uv.x, mod(uv.y, 1024.))*I512 - 1., tcSign);
    if (uv.y > 4096.) tcD = tcD.xzy;
    else if (uv.y > 2048.) tcD = tcD.zxy;
    return textureLod(iChannel3, tcD, 0.);
}

vec4 TextureCube(vec2 uv, float lod) {
    float tcSign = -mod(floor(uv.y*I1024), 2.)*2. + 1.;
    vec3 tcD = vec3(vec2(uv.x, mod(uv.y, 1024.))*I512 - 1., tcSign);
    if (uv.y > 4096.) tcD = tcD.xzy;
    else if (uv.y > 2048.) tcD = tcD.zxy;
    return textureLod(iChannel3, tcD, lod);
}

vec3 IntegrateVoxel(vec3 p, vec3 n) {
    vec3 l = vec3(0.);
    vec2 cubeUV = vec2(p.x + floor(p.y)*32., p.z);
    float normalOffset;
    vec3 an = abs(n);
    if (an.x > max(an.y, an.z)) normalOffset = ((n.x < 0.)? 0. : 48.)*9.;
    else if (an.y > an.z) normalOffset = ((n.y < 0.)? 48.*2. : 48.*3.)*9.;
    else normalOffset = ((n.z < 0.)? 48.*4. : 48.*5.)*9.;
    for (float i = 0.; i < 8.5; i++) {
        l += TextureCube(cubeUV + vec2(0., normalOffset + i*48.)).xyz;
    }
    return l;
}

float SampleShadow(vec3 p, vec3 n, vec3 SUN_DIR) {
    vec3 SUN_TAN = normalize(cross(SUN_DIR, vec3(0., 1., 0.)));
    vec3 SUN_BIT = cross(SUN_TAN, SUN_DIR);
    vec3 smPos = p - (vec3(16., 16., 24.) + SUN_DIR*SUN_DIST);
    vec2 smUV = vec2(dot(smPos, SUN_TAN), dot(smPos, SUN_BIT))/SUN_SM_SIZE/ASPECT*0.5 + 0.5;
    return float(texture(iChannel2, smUV).w > dot(smPos, -SUN_DIR));
}

vec4 NearestCS(vec3 fPos, vec2 lFaceUV, vec3 lSize, vec4 lDIUV0, vec4 lDIUV1,
               vec3 vPos, float lLF, float lOff, float lPS, float lPow4) {
    vec2 lVolumeUV = vec2(fPos.x + fPos.y*lSize.x + 0.5, fPos.z + 0.5);
    vec3 rlPos = (fPos + 0.5)*lLF;
    vec3 rPos = vPos - rlPos;
    vec3 aPos = abs(rPos);
    vec2 oFaceUV = vec2(0., lOff);
    if (aPos.x > max(aPos.y, aPos.z)) {
        oFaceUV.y += ((rPos.x < 0.)? 0. : 1.)*9.*lSize.z;
        rPos = vec3(rPos.zy, aPos.x);
    } else if (aPos.y > aPos.z) {
        oFaceUV.y += ((rPos.y < 0.)? 2. : 3.)*9.*lSize.z;
        rPos = vec3(rPos.xz, aPos.y);
    } else {
        oFaceUV.y += ((rPos.z < 0.)? 4. : 5.)*9.*lSize.z;
        rPos = vec3(rPos.xy, aPos.z);
    }
    vec2 projUV = ProjectDir(rPos, lPS);
    float oDirIndex = projUV.x + floor(projUV.y)*lPS;
    vec2 oDirUV = vec2(floor(mod(oDirIndex, lPow4))*lSize.x*lSize.y, floor(oDirIndex/lPow4)*lSize.z);
    float projectedRayLen = TextureCube(oFaceUV + oDirUV + lVolumeUV).w;
    if (projectedRayLen < length(rPos) - 0.5) return vec4(0., 0., 0., 0.00001);
    vec4 lOut = TextureCube(lFaceUV + lDIUV0.xy + lVolumeUV) +
                TextureCube(lFaceUV + lDIUV0.zw + lVolumeUV) +
                TextureCube(lFaceUV + lDIUV1.xy + lVolumeUV) +
                TextureCube(lFaceUV + lDIUV1.zw + lVolumeUV);
    if (lOut.w < -0.5) return vec4(lOut.xyz*0.001, 0.001);
    return vec4(lOut.xyz, 1.);
}

vec4 TrilinearCS(vec3 lPos, vec2 lFaceUV, float lDirIndex, float lProbeSize,
                 vec3 lSize, float lPow4, vec3 vPos, float lLF, float lOff) {
    vec4 lDIUV0 = vec4(floor(mod(lDirIndex, lPow4))*lSize.x*lSize.y, floor(lDirIndex/lPow4)*lSize.z,
                       floor(mod(lDirIndex + 1., lPow4))*lSize.x*lSize.y, floor((lDirIndex + 1.)/lPow4)*lSize.z);
    vec4 lDIUV1 = vec4(floor(mod(lDirIndex + lProbeSize, lPow4))*lSize.x*lSize.y,
                       floor((lDirIndex + lProbeSize)/lPow4)*lSize.z,
                       floor(mod(lDirIndex + lProbeSize + 1., lPow4))*lSize.x*lSize.y,
                       floor((lDirIndex + lProbeSize + 1.)/lPow4)*lSize.z);
    vec3 fPos = clamp(floor(lPos - 0.5), vec3(0.), lSize - 2.);
    vec3 frPos = min(vec3(1.), lPos - 0.5 - fPos);
    vec4 l000 = NearestCS(fPos, lFaceUV, lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l100 = NearestCS(vec3(fPos.x + 1., fPos.y, fPos.z), lFaceUV,
                          lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l010 = NearestCS(vec3(fPos.x, fPos.y + 1., fPos.z), lFaceUV,
                          lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l110 = NearestCS(vec3(fPos.x + 1., fPos.y + 1., fPos.z), lFaceUV,
                          lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l001 = NearestCS(vec3(fPos.x, fPos.y, fPos.z + 1.), lFaceUV,
                          lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l101 = NearestCS(vec3(fPos.x + 1., fPos.y, fPos.z + 1.), lFaceUV,
                          lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l011 = NearestCS(vec3(fPos.x, fPos.y + 1., fPos.z + 1.), lFaceUV,
                          lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    vec4 l111 = NearestCS(fPos + 1., lFaceUV, lSize, lDIUV0, lDIUV1, vPos, lLF, lOff, lProbeSize, lPow4);
    float lweight = mix(mix(mix(l000.w, l100.w, frPos.x), mix(l010.w, l110.w, frPos.x), frPos.y),
                    mix(mix(l001.w, l101.w, frPos.x), mix(l011.w, l111.w, frPos.x), frPos.y), frPos.z);
    return vec4(mix(mix(mix(l000.xyz, l100.xyz, frPos.x), mix(l010.xyz, l110.xyz, frPos.x), frPos.y),
                    mix(mix(l001.xyz, l101.xyz, frPos.x), mix(l011.xyz, l111.xyz, frPos.x), frPos.y),
                    frPos.z)/lweight, lweight);
}

bool OutsideGeo(vec3 sp) {
    vec3 p = floor(sp) + 0.5;
    return (texture(iChannel1, vec2(p.x + floor(mod(p.y, 8.))*32., p.z + floor(p.y*0.125)*48.)*IRES).w < 0.5);
}

vec3 GeoOffset(vec3 vertex) {
    for (float x = -0.5; x < 1.; x++) {
        for (float y = -0.5; y < 1.; y++) {
            for (float z = -0.5; z < 1.; z++) {
                if (OutsideGeo(vertex + vec3(x, y, z))) return vec3(x, y, z)*0.1;
            }
        }
    }
    return vec3(0.001);
}

vec4 Trace(vec3 p, vec3 d, out vec3 pPos, out vec4 pCol) {
    vec4 info = vec4(vec3(0.), 100000.);
    vec3 signdir = (max(vec3(0.), sign(d))*2. - 1.);
    vec3 iDir = 1./d;
    float bbDF = DFBox(p, vec3(32., 32., 48.));
    vec2 bb = ABox(p, iDir, vec3(0.01), vec3(31.99, 31.99, 47.99));
    if (bbDF > 0. && (bb.x < 0. || bb.y < bb.x)) return vec4(-10.);
    float tFAR = bb.y;
    float t = ((bbDF < 0.)? 0. : bb.x + 0.001);
    vec3 cp;
    vec4 sC;
    vec3 fp = floor(p + d*t);
    vec3 lfp = fp - vec3(0., 1., 0.);
    for (int i = 0; i < 128; i++) {
        if (t > tFAR) break;
        cp = p + d*t;
        sC = texture(iChannel1, vec2(fp.x + (mod(fp.y + 0.5, 8.) - 0.5)*32. + 0.5, fp.z + floor(fp.y*0.125)*48. + 0.5)*IRES);
        if (sC.w > 0.5) {
            pPos = lfp + 0.5;
            pCol = sC;
            return vec4(lfp - fp, t);
        }
        lfp = fp;
        fp += ABoxfarNormal(p, iDir, signdir, fp, fp + 1., t);
    }
    return vec4(-10.);
}

void mainCubemap(out vec4 fragColor, in vec2 fragCoord, in vec3 rayOri, in vec3 rayDir) {
    vec4 info = texture(iChannel3, rayDir);
    vec2 uv; vec3 aDir = abs(rayDir);
    if (aDir.z > max(aDir.x, aDir.y)) {
        //Z-side
        uv = floor(((rayDir.xy/aDir.z)*0.5 + 0.5)*1024.) + 0.5;
        if (rayDir.z < 0.) uv.y += 1024.;
    } else if (aDir.x > aDir.y) {
        //X-side
        uv = floor(((rayDir.yz/aDir.x)*0.5 + 0.5)*1024.) + 0.5;
        if (rayDir.x > 0.) uv.y += 2048.;
        else uv.y += 3072.;
    } else {
        //Y-side
        uv = floor(((rayDir.xz/aDir.y)*0.5 + 0.5)*1024.) + 0.5;
        if (rayDir.y > 0.) uv.y += 4096.;
        else uv.y += 5120.;
    }

    //Cascades
    if (uv.y < LOD_MAX_POS) {
        float vLod = 0.;
        vec2 vuv = uv;
        float lOffset = 2592.;
        for (int i = 1; i < 5; i++) {
            lOffset = LOD_POS[i];
            if (uv.y > lOffset) {
                vLod += 1.;
            } else {
                vuv.y -= LOD_POS[i - 1];
                break;
            }
        }
        float vLodFactor = pow(2., vLod);
        float vILodFactor = 1./vLodFactor;
        float vProbeSize = 3.*vLodFactor;
        vec3 vSize = vec3(32., 32., 48.)*vILodFactor;
        vec3 vISize = vec3(I32, I32, I48)*vLodFactor;
        float vFace = mod(floor(vuv.y*vISize.z*I9) + 0.5, 6.);
        float vDirIndex = floor(mod(vuv.y*vISize.z, 9.))*pow(4., vLod) + floor(vuv.x*vISize.x*vISize.y) + 0.5;
        vec3 vPos = vec3(mod(vuv.x, vSize.x), mod(floor(vuv.x*vISize.x) + 0.5, vSize.y), mod(vuv.y, vSize.z))*vLodFactor;
        vec3 vN, vT, vB;
        if (vFace < 2.) {
            vT = vec3(0., 0., 1.);
            vB = vec3(0., 1., 0.);
            vN = vec3(((vFace < 1.)? -1. : 1.), 0., 0.);
        } else if (vFace < 4.) {
            vT = vec3(1., 0., 0.);
            vB = vec3(0., 0., 1.);
            vN = vec3(0., ((vFace < 3.)? -1. : 1.), 0.);
        } else {
            vT = vec3(1., 0., 0.);
            vB = vec3(0., 1., 0.);
            vN = vec3(0., 0., ((vFace < 5.)? -1. : 1.));
        }
        if (vLod > 0.5) {
            vPos += GeoOffset(vPos);
        } else {
            vPos -= vN*0.25;
        }
        if (OutsideGeo(vPos)) {
            info = vec4(0., 0., 0., 1.);
            vec2 vDirUV = vec2(mod(vDirIndex, vProbeSize), floor(vDirIndex/vProbeSize) + 0.5);
            vec3 vDir = ComputeDir(vDirUV, vProbeSize);
            vDir = vT*vDir.x + vB*vDir.y + vN*vDir.z;
            vec3 pPos; vec4 pCol;
            vec4 vHit = Trace(vPos, vDir, pPos, pCol);
            if (vHit.x > -1.5) {
                info.w = vHit.w;
                if (pCol.w > 1.5) {
                    info.xyz = pCol.xyz;
                } else {
                    vec3 SUN_DIR = GetSunDir(iTime);
                    float sunDot = dot(SUN_DIR, vHit.xyz);
                    if (sunDot > 0.) info.xyz += SampleShadow(pPos, vHit.xyz, SUN_DIR)*sunDot*GetSunLight(iTime);
                    info.xyz += IntegrateVoxel(floor(pPos - vDir*0.001) + 0.5, vHit.xyz);
                    info.xyz *= pCol.xyz;
                }
            } else {
                info.w = 10000000.;
                info.xyz += GetSkyLight(vDir, iTime);
            }

            //Normalized area * cos(theta)
            if (vLod < 0.5) {
                if (length(vDirUV) > 0.75) {
                    info.xyz *= cos(0.25*3.141592653)/8.;
                } else {
                    info.xyz *= (1. - cos(0.25*3.141592653));
                }
            } else {
                vec2 vProbeRel = vDirUV - vProbeSize*0.5;
                float vProbeThetai = max(abs(vProbeRel.x), abs(vProbeRel.y));
                float vProbeTheta = acos(dot(vDir, vN));
                info.xyz *= (cos(vProbeTheta - 0.5*3.141592653/vProbeSize) -
                             cos(vProbeTheta + 0.5*3.141592653/vProbeSize))/(4. + 8.*floor(vProbeThetai));
            }
            info.xyz *= dot(vDir, vN);

            //Merging
            vec3 lSize = vSize*0.5;
            vec3 lISize = vISize*2.;
            float lProbeSize = vProbeSize*2.;
            if (vLod < 3.5*0. + 3.5) {
                float lPow4 = pow(4., vLod + 1.);
                vec3 lPos = clamp(vPos*vILodFactor*0.5, vec3(0.5), lSize - 0.5);
                vec2 lFaceUV = vec2(0., lOffset + 9.*lSize.z*floor(vFace));
                float lDirIndex0 = floor(vDirUV.x)*2. + floor(vDirUV.y)*lProbeSize*2. + 0.5;
                vec4 lLight = TrilinearCS(lPos, lFaceUV, lDirIndex0, lProbeSize, lSize, lPow4, vPos, vLodFactor*2., lOffset);
                float distInterp = clamp((info.w - vLodFactor)*vILodFactor*0.5, 0., 1.);
                info.xyz = mix(info.xyz, lLight.xyz, distInterp);
            }
        } else {
            info = vec4(0., 0., 0., -1.);
        }
    } else {
        discard;
    }
    fragColor = info;
}

//Volume (32 x 32 x 48)

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec4 info = texture(iChannel1, fragCoord*IRES);
    if (DFBox(fragCoord, vec2(256., 192.)) < 0.) {
        vec3 vPos = vec3(mod(fragCoord.x, 32.), floor(fragCoord.x*I32) + floor(fragCoord.y*I48)*8. + 0.5, mod(fragCoord.y, 48.));
        vec3 modP = vec3(vPos.xy, mod(vPos.z, 16.));
        info = vec4(0.);

        //Stone color
        vec3 stoneColor = vec3(0.95, 0.925, 0.9);

        //Bounding box
        if (DFBox(vPos - vec3(1., 1., 1.), vec3(30., 100., 46.)) > 0.) info = vec4(stoneColor, 1.);

        //Floor
        if (vPos.y < 2. && fract(dot(vPos.xz, vec2(0.707))*0.125) > 0.35 &&
            fract(dot(vPos.xz, vec2(0.707, -0.707))*0.125) > 0.35) info = vec4(stoneColor, 1.);
            //Temporal emissive
            if (info.w > 0.5 && abs(vPos.y - 1.5) < 0.5 &&
                length(vPos.xz - vec2(8., 8. + (sin(iTime - 1.5)*0.5 + 0.5)*24.)) < 5.)
                info = vec4(1.5, 0.7, 0.2, 2.);

        //Columns
        if (length(vec2(vPos.x - 16., mod(vPos.z + 8., 16.) - 8.)) < 2.) info = vec4(stoneColor, 1.);
            //Arcs
            if (vPos.y > 19.) modP.y -= 16.;
            if (DFBox(vec3(vPos.x, modP.y, vPos.z) - vec3(14., 9., 0.), vec3(3., 10., 32.)) < 0. &&
                length(modP.zy - vec2(8., 8.)) - abs(vPos.x - 15.5) > 6.) info = vec4(stoneColor, 1.);
            if (DFBox(vec3(vPos.x, modP.y, vPos.z) - vec3(16., 9., 30.), vec3(16., 10., 3.)) < 0. &&
                length(modP.xy - vec2(24., 8.)) - abs(vPos.z - 31.5) > 6.) info = vec4(stoneColor, 1.);
            //Cloth
            if (vPos.z < 32.) {
                vec3 aPos = vec3(abs(vPos.x - 18.), vPos.y, abs(vPos.z - 8.));
                if (DFBox(vPos - vec3(17., 3., 1.), vec3(2., 13., 14.)) < 0. &&
                    abs(vPos.x - (18.5 - float(vPos.y > 15. || aPos.z > 20. - vPos.y
                    || aPos.z < 2. + (17. - vPos.y)*(17. - vPos.y)*0.02))) < 0.25 &&
                    aPos.z > 1. + (17. - vPos.y)*(17. - vPos.y)*0.02) info = vec4(0.99, 0.4, 0.4, 1.);
                aPos = vec3(abs(vPos.x - 18.), vPos.y, abs(vPos.z - 24.));
                if (DFBox(vPos - vec3(17., 3., 17.), vec3(2., 13., 14.)) < 0. &&
                    abs(vPos.x - (18.5 - float(vPos.y > 15. || aPos.z > 20. - vPos.y
                    || aPos.z < 2. + (17. - vPos.y)*(17. - vPos.y)*0.02))) < 0.25 &&
                    aPos.z > 1. + (17. - vPos.y)*(17. - vPos.y)*0.02) info = vec4(0.4, 0.99, 0.4, 1.);
            }

        //Second floor
        if (DFBox(vPos - vec3(0., 15., 0.), vec3(16., 1., 48.)) < 0.) info = vec4(stoneColor, 1.);
        if (DFBox(vPos - vec3(0., 15., 32.), vec3(32., 1., 16.)) < 0.) info = vec4(stoneColor, 1.);
            //Inner arc
            if (vPos.x < 16. && mod(vPos.y, 16.) > 15. - pow(0.22*length(vec2(vPos.x - 8., modP.z - 8.)), 2.) &&
                length(modP - vec3(12., 5., 8.)) > 10.) info = vec4(stoneColor, 1.);
            if (vPos.x > 16. && vPos.z > 32. && mod(vPos.y, 16.) > 15. - pow(0.22*length(vec2(vPos.x - 24., modP.z - 8.)), 2.) &&
                length(modP - vec3(24., 5., 4.)) > 10.) info = vec4(stoneColor, 1.);
            //Fountain (?)
            if (vPos.y < 7. && length(vPos.xz - vec2(8., 40.)) < 2. + floor((vPos.y - 1.)*0.5) &&
                vPos.y < 3. + length(vPos.xz - vec2(8., 40.))) info = vec4(stoneColor, 1.);
                //Lamp above
                if (length(vec2(length(vPos.xz - vec2(8., 40.)) -
                    3.5 - floor((13.5 - vPos.y)*0.333), vPos.y - 13.5)) < 0.5) info = vec4(0.8, 0.6, 0.2, 2.);
                float lA = iTime;

        //X+ wall (bricks)
        if (vPos.x < 2. && mod(vPos.z + floor((vPos.y + 1.)/4.)*2., 4.) > 1. &&
            mod(vPos.y - 1., 4.) > 2.) info = vec4(stoneColor, 1.);

        //Z- wall (lion approx)
        if (smin(length(vPos - vec3(24., 8., 51.)) - 6.,
            length(vPos - vec3(24., 7., 45.5)) - 2., 4.) < 0. &&
            length(vec3(abs(vPos.x - 24.) - 2., vPos.y - 9., vPos.z - 44.)) > 1.) info = vec4(stoneColor, 1.);

        //Z+ wall
        if (vPos.x > 16.) {
            if (length(vec3(mod(vPos.x + 1., 8.) - 4., mod(vPos.y, 8.) - 4., vPos.z - 0.15)) < 2.5) info = vec4(stoneColor, 1.);
        }

        //Ceiling
        if (DFBox(vPos - vec3(0., 30., 0.), vec3(16., 2., 48.)) < 0.) info = vec4(stoneColor, 1.);
        if (DFBox(vPos - vec3(0., 30., 32.), vec3(32., 2., 16.)) < 0.) info = vec4(stoneColor, 1.);

        //Dynamic sphere
        if (length(vPos - vec3(8. + (sin(iTime - 0.3)*0.5 + 0.5)*19., 24., 8.)) < 4.) info = vec4(0.5, 0.6, 0.9, 1.);
    }
    fragColor = info;
}

